mapper.select:
SELECT rp.*, s.class_id,
       (SELECT c.class_name FROM "class" c WHERE c.id = s.class_id) as "className"
FROM reward_punish rp
LEFT JOIN student s ON rp.student_id = s.id
WHERE 1=1

    AND (rp.student_no LIKE CONCAT('%', #{query.keyword}, '%')
         OR rp.student_name LIKE CONCAT('%', #{query.keyword}, '%'))

AND rp.student_id = #{query.studentId}
AND rp.type = #{query.type}
AND rp.record_date >= #{query.dateStart}
AND rp.record_date <= #{query.dateEnd}
ORDER BY rp.create_time DESC
